{
  "model_name": "{{model_name}}",
  "prompts": [
    "Write a one-sentence summary of Retrieval-Augmented Generation.",
    "Give me 3 bullet points on why quantization helps inference latency."
  ],
  "sampling": {
    "temperature": 0.2,
    "top_p": 0.9,
    "max_tokens": 128
  }
}

{
  "model_name": "{{model_name}}",
  "prompts": [
    {
      "messages": [
        {
          "role": "system",
          "content": "You are a concise assistant."
        },
        {
          "role": "user",
          "content": "Give me a 2-step plan to debug CUDA OOM issues."
        }
      ],
      "metadata": {
        "id": "chat-1"
      }
    },
    {
      "messages": [
        {
          "role": "user",
          "content": "Rewrite this sentence in plain English: 'The model exhibited non-deterministic behavior under stochastic decoding.'"
        }
      ],
      "metadata": {
        "id": "chat-2"
      }
    }
  ],
  "sampling": {
    "temperature": 0.3,
    "top_p": 0.95,
    "max_tokens": 180
  },
  "output_field": "output"
}
